<div class="page-head"><div><h2>Onboarding</h2><p class="muted">Checklist onboarding, approval progress, and audit trail.</p></div></div>
<div class="grid grid-2"><div class="card"><h3>Create Task</h3><form method="post" action="<?=url('/onboarding/store')?>"><?=csrf_field()?><div class="form-row"><div><label>Employee</label><select name="employee_id"><?php foreach($employees as $e): ?><option value="<?=e($e['id'])?>"><?=e($e['full_name'])?></option><?php endforeach; ?></select></div><div><label>Task Name</label><input name="task_name" required></div><div><label>Due Date</label><input name="due_date" type="date"></div><div><label>Status</label><select name="status"><option>open</option><option>in_progress</option><option>done</option><option>blocked</option></select></div></div><br><button class="btn btn-primary">Save Task</button></form></div><div class="card"><h3>Report</h3><div class="grid grid-3"><div><div class="muted">Tasks</div><div class="stat"><?=count($rows)?></div></div><div><div class="muted">Open</div><div class="stat"><?=count(array_filter($rows,fn($r)=>$r['status']==='open'))?></div></div><div><div class="muted">Done</div><div class="stat"><?=count(array_filter($rows,fn($r)=>$r['status']==='done'))?></div></div></div></div></div><br>
